import Foundation

class AnalyticsModule {
    private let logger = Logger()

    func logUserInteraction(userID: String, action: String) {
        logger.log("User \(userID) performed action '\(action)'")
    }

    func logAPICall(url: URL, method: String, payload: Data?) {
        let request = NSMutableURLRequest(url: url, cachePolicy: .useProtocolCachePolicy, timeoutInterval: 60.0)
        request.httpMethod = method
        if let payload = payload {
            request.httpBody = payload
        }
        logger.log("Made API call to \(url) with method '\(method)' and payload \(String(describing: payload))")
    }

    func logUserDataChange(userID: String, dataType: String, newValue: Any?) {
        let value = newValue ?? "nil"
        logger.log("User \(userID) changed '\(dataType)' to '\(value)'")
    }

    func logErrorCondition(error: Error) {
        logger.log("Encountered error: \(error)")
    }
}

class Logger {
    private let fileManager = FileManager()
    private let logFileURL: URL

    init(fileURL: URL? = nil) {
        if let url = fileURL {
            self.logFileURL = url
        } else {
            self.logFileURL = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!.appendingPathComponent("analytics_log.txt")
        }
    }

    func log(_ message: String) {
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd HH:mm:ss"
        let timestamp = dateFormatter.string(from: Date())
        let logMessage = "\(timestamp) - \(message)\n"
        do {
            try logMessage.write(toFile: logFileURL, atomically: true, encoding: .utf8)
        } catch {
            print("Error writing to log file: \(error)")
        }
    }
}